const raw = $input.first().json;
const b = raw.body || raw;
if (b.message_type && b.message_type !== 'incoming') return [];
if (b.private) return [];

const conv = b.conversation || {};
const sender = conv?.meta?.sender || b.sender || {};
let phone = (sender.phone_number || sender.identifier || '').replace(/[^0-9+]/g,'').replace(/^\+/,'');
if (phone.startsWith('00')) phone = phone.slice(2);

const atts = b.attachments || b.message?.attachments || [];
let mediaType = 'text', mediaUrl = '';
if (atts.length) {
  const a = atts[0];
  mediaUrl = a.data_url || a.file_url || '';
  if ((a.file_type||'').includes('audio')) mediaType = 'voice';
  else if ((a.file_type||'').includes('image')) mediaType = 'image';
}

const text = (b.content || b.message?.content || '').trim();
if (!phone) return [];
if (mediaType === 'text' && !text) return [];

return [{ json: {
  client_id:  String(raw.client_id || b.client_id || ''),
  account_id: String(b.account?.id || conv?.account_id || ''),
  inbox_id:   String(b.inbox?.id || conv?.inbox_id || ''),
  convId:     conv?.id || null,
  phone, name: sender.name || '', text, mediaType, mediaUrl,
  _startMs: Date.now()
} }];

const msg = $('Code · Parse').first().json;
const raw = $input.first().json;
const t = raw.list ? raw.list[0] : raw;
if (!t || !t.chatwoot_inbox_id) return [];
if (t.active === 'No') return [];
let flow = {}; try { flow = JSON.parse(t.flow_json || '{}'); } catch(e) {}
let botConfig = {}; try { botConfig = JSON.parse(t.bot_config || '{}'); } catch(e) {}
let qualQuestions = []; try { qualQuestions = JSON.parse(t.qual_questions || '[]'); } catch(e) {}
let services = []; try { services = JSON.parse(t.services || '[]'); } catch(e) {}
const kb_summary = t.kb_summary || '';
return [{ json: {
  ...msg,
  chatwoot_base: t.chatwoot_base, chatwoot_account_id: t.chatwoot_account_id, chatwoot_token: t.chatwoot_token,
  control_nocodb_base: 'https://whizz.aiingo.com', control_nocodb_token: 'nc_pat_n5dMpFolDUQNtkCWGiCJnX45xXWUoFnZdsQkwEyF',
  analytics_table_id: 'm2in19v8n7phitr',
  openrouter_key: t.openrouter_key || $env.OPENROUTER_KEY, model: t.model || 'google/gemini-2.5-flash',
  language: t.language || 'ml', main_prompt: t.main_prompt || '', flow,
  botConfig, qualQuestions, services, kb_summary,
  client_name: t.client_name || '',
  sarvam_key: t.sarvam_key || $env.SARVAM_API_KEY || '',
  cal_link: t.cal_link || '',
  sarvam_lang: ({ml:'ml-IN',hi:'hi-IN',ta:'ta-IN',te:'te-IN',bn:'bn-IN',kn:'kn-IN',mr:'mr-IN',gu:'gu-IN'})[t.language||'ml'] || 'ml-IN',
  test_mode: t.test_mode || 'No',
  test_phone: t.test_phone || ''
} }];

const c = $('Code · Build ctx').first().json;
const r = $input.first().json;
const rows = r.list || [];
const lead = rows.find(l => String(l.ClientId) === String(c.client_id)) || null;
// Opt-out: block opted-out leads (allow START to re-subscribe)
const msg = $('Code · Parse').first().json;
if (lead?.OptOut === 'Yes') {
  const _txt = (msg.text || '').trim().toLowerCase();
  if (_txt !== 'start') return [];
}
if (lead && (lead.Handover === 'Yes' || lead.Stage === 'human_handover')) return [];
if (c.test_mode === 'Yes' && c.test_phone && c.phone !== c.test_phone.replace(/[^0-9]/g,'')) return [];

const rateLimitMs = parseInt(c.botConfig?.rate_limit_ms) || 4000;
const lastMsgAt = lead?.LastMsgAt ? new Date(lead.LastMsgAt).getTime() : 0;
if (Date.now() - lastMsgAt < rateLimitMs) return [];

const duplicateClientIds = rows.filter(l => String(l.ClientId) !== String(c.client_id)).map(l => String(l.ClientId));
const isDuplicate = duplicateClientIds.length > 0;

let history = [];
try { history = JSON.parse(lead?.ConvHistory || '[]'); } catch(e) {}
const botMsgs = history.filter(m => m.role === 'assistant').slice(-3).map(m => m.content);
const looping = botMsgs.length === 3 && botMsgs.every(m => m === botMsgs[0]);

const memSummary = lead?.MemSummary || '';
const activeHistory = history.length > 20 ? history.slice(-6) : history;

let qualAnswers = {};
try { qualAnswers = JSON.parse(lead?.QualAnswers || '{}'); } catch(e) {}

return [{ json: { ...c, leadId: lead?.Id || null, stage: lead?.Stage || 'new', history, activeHistory, memSummary, looping, qualAnswers, isDuplicate, leadOptOut: lead?.OptOut || 'No' } }];

const c = $('Code · State').first().json;
const r = $input.first().json;
const txt = r.choices?.[0]?.message?.content || '(image received)';
return [{ json: { ...c, userText: txt } }];

const c = $('Code · State').first().json;
const r = $input.first().json;
// Sarvam STT returns { transcript: '...' }, OpenRouter returns choices[]
const txt = r.transcript || r.choices?.[0]?.message?.content || '(voice note received)';
return [{ json: { ...c, userText: txt } }];

const c = $input.first().json;
// AI Agent output is {output:'...'}, get userText from Code · Merge text
const mergeCtx = $('Code · Merge text').first().json;
const userText = mergeCtx.userText || '';
// Opt-out detection
const _OPT_OUT = ['stop','unsubscribe','opt out','opt-out','optout'];
const _isOptOut = _OPT_OUT.some(w => userText.toLowerCase().trim() === w);
const _isResub = userText.toLowerCase().trim() === 'start' && sc.leadOptOut === 'Yes';
if (_isOptOut) return [{ json: { ...sc, userText, intent:'SHORT_NEUTRAL', route:'qualify_next', reply:'You have been unsubscribed. Reply START to re-subscribe.', next: sc.stage, qualAnswers: sc.qualAnswers||{}, _isOptOut:true } }];
if (_isResub) return [{ json: { ...sc, userText, intent:'SHORT_NEUTRAL', route:'qualify_next', reply:'Welcome back! You are re-subscribed.', next: 'new', qualAnswers: sc.qualAnswers||{}, _isResub:true } }];

// Support both n8n AI node output and raw OpenAI HTTP response
const raw = c.output || c.text || c.choices?.[0]?.message?.content || '';
let intent = 'SHORT_NEUTRAL', intentData = {};
try {
  const m = raw.replace(/```json|```/gi,'').match(/\{[\s\S]*\}/);
  if (m) { const p = JSON.parse(m[0]); intent = p.intent || intent; intentData = p.data || {}; }
} catch(e) {}
const valid = ['DELAY','BOOKING','AFFIRMATIVE','WATCHED','FORM_DONE','WANTS_MORE_INFO','QUESTION','WANTS_HUMAN','SHORT_NEUTRAL'];
if (!valid.includes(intent)) intent = 'SHORT_NEUTRAL';

const sc = $('Code · State').first().json;
if (sc.looping && sc.botConfig?.antiloop_enabled !== false) intent = 'WANTS_HUMAN';

const qs = sc.qualQuestions || [];
const qualDone = !qs.length || sc.botConfig?.qual_enabled === false || (sc.stage && !sc.stage.startsWith('qual_') && sc.stage !== 'new');
const qualStage = sc.stage?.startsWith('qual_') ? parseInt(sc.stage.replace('qual_','')) : null;

// Flow lookup — only fall back to 'new' when stage IS 'new', otherwise route to FAQ
const flow = sc.flow || {};
const stageNode = flow.stages?.[sc.stage];
const node = stageNode || (sc.stage === 'new' || !sc.stage ? flow.stages?.['new'] : null) || {};
const stageNotFound = !stageNode && sc.stage && sc.stage !== 'new';

// After human handover: allow up to 3 FAQ answers then go silent
const _isPostHandover = sc.stage === 'human_handover';
const _handoverFaqCount = sc.handoverFaqCount || 0;
const action = node[intent] || node['*'] || { next: sc.stage, msg: null };

const POSITIVE = new Set(['AFFIRMATIVE','WATCHED','FORM_DONE','BOOKING','SHORT_NEUTRAL']);
const NEGATIVE = new Set(['DELAY','WANTS_MORE_INFO']);

// Detect final stage (last stage key that is not 'new')
const _allStages = Object.keys(flow.stages || {}).filter(k => k !== 'new');
const _isFinalStage = _allStages.length > 0 && sc.stage === _allStages[_allStages.length - 1];

// Detect if bot already sent the same message (avoid repeat)
const _lastBotMsg = (sc.history || []).filter(m => m.role === 'assistant').slice(-1)[0]?.content || '';
const _actionMsg = action.msg ? (flow.messages?.[action.msg] || '') : '';
const _wouldRepeat = _actionMsg && _lastBotMsg && _lastBotMsg.includes(_actionMsg.slice(0, 40));

let reply = '', videoUrl = null;
let route = 'stage';
if (intent === 'WANTS_HUMAN' && sc.botConfig?.handover_enabled !== false) route = 'human';
// Auto handover: final stage + customer affirms → hand to human with callback message
else if (_isFinalStage && POSITIVE.has(intent) && sc.botConfig?.handover_enabled !== false) {
  route = 'human';
  // Calculate next business day 9am in client timezone
  const _tz = sc.botConfig?.timezone || 'Asia/Kolkata';
  const _now = new Date();
  const _nowLocal = new Date(_now.toLocaleString('en-US', { timeZone: _tz }));
  const _hour = _nowLocal.getHours();
  const _day = _nowLocal.getDay(); // 0=Sun,6=Sat
  let _callLabel = 'tomorrow';
  // If before 9am on a weekday → same day
  if (_hour < 9 && _day >= 1 && _day <= 5) _callLabel = 'today';
  // If Saturday → Monday
  else if (_day === 6) _callLabel = 'on Monday';
  // If Sunday → tomorrow (Monday)
  else if (_day === 0) _callLabel = 'tomorrow (Monday)';
  const _callbackMsg = sc.botConfig?.callback_msg ||
    `Thank you! 🙏 Our team will contact you ${_callLabel} at 9am. We look forward to speaking with you!`;
  reply = _callbackMsg;
}
// Avoid repeat: same message would be sent again → go FAQ instead
else if (_wouldRepeat && POSITIVE.has(intent)) route = 'faq';
else if (_isPostHandover) {
  if (_handoverFaqCount < 3) route = 'faq';
  else route = 'drop';
} else if (stageNotFound || intent === 'QUESTION' || NEGATIVE.has(intent)) route = 'faq';
else if (!qualDone && qualStage === null) route = 'qualify';
else if (!qualDone && qualStage !== null) route = 'qualify_next';

let next = action.next || sc.stage;
let qualAnswers = sc.qualAnswers || {};

if (route === 'qualify_next') {
  const currentIdx = qualStage !== null ? qualStage : 0;
  const nextIdx = currentIdx + 1;
  if (qs[currentIdx]) qualAnswers[qs[currentIdx]] = userText;
  if (nextIdx < qs.length) {
    reply = qs[nextIdx];
    next = 'qual_' + nextIdx;
  } else {
    const firstStage = Object.keys(flow.stages || {}).filter(k => k !== 'new')[0] || 'new';
    const firstAction = (flow.stages?.[firstStage] || {})['*'] || { next: firstStage, msg: null };
    const vars = flow.variables || {};
    reply = (flow.messages?.[firstAction.msg] || 'Great, thanks! Let me share some information 😊').replace(/\[(\w+)\]/g, (_,k)=> vars[k] ?? '');
    next = firstAction.next || firstStage;
  }
} else if (route === 'stage' && action.msg) {
  const vars = flow.variables || {};
  reply = (flow.messages?.[action.msg] || '').replace(/\[(\w+)\]/g, (_,k)=> vars[k.toLowerCase()] ?? vars[k] ?? '');
  if (action.form && vars.form_link && !reply.includes(vars.form_link)) reply += '\n\n' + vars.form_link;
  if (action.video) videoUrl = vars[action.video] || null;
}
if (route === 'stage' && !action.msg) route = 'faq';

// Auto-append Cal.com booking link on BOOKING intent
if (intent === 'BOOKING' && sc.cal_link && !reply.includes(sc.cal_link)) {
  reply = (reply || 'Great! You can book your slot here 📅') + '\n\n👉 ' + sc.cal_link;
}
return [{ json: { ...sc, userText, intent, intentData, route, next, reply, videoUrl, qualStage, qualAnswers } }];

const c = $input.first().json;
const history = c.activeHistory || [];
const lang = c.language || 'en';
let sys = c.main_prompt || '';
if (c.services && c.services.length) {
  const svcLines = c.services.map(s =>
    `- ${s.name}: ${s.description||''} | Price: ${s.currency||'AED'} ${s.price} per ${s.per||'person'}`
  ).join('\n');
  sys += '\n\n## Services\n' + svcLines;
}
if (c.kb_summary && c.kb_summary.trim()) {
  sys += '\n\n## Knowledge Base\n' + c.kb_summary.slice(0, 2000);
}
if (history.length) {
  const histText = history.slice(-3).map(m => m.role+': '+m.content).join('\n');
  sys += '\n\n## Recent Conversation\n' + histText;
}
sys += '\n\nCurrent stage: ' + (c.stage || 'new') + '. Respond ONLY in ' + lang + '. Never switch languages. For any question not answerable from your knowledge, politely say you will connect them with an advisor.';
return [{ json: { ...c, _systemPrompt: sys } }];

const c = $('Code · FAQ prep').first().json;
const r = $input.first().json;
const reply = r.output || r.text || r.choices?.[0]?.message?.content?.trim() || 'One moment 🙏';
return [{ json: { ...c, reply } }];

const c = $input.first().json;
const qs = c.qualQuestions || [];
const question = qs[0] || 'Could you tell me a bit more about what you are looking for?';
return [{ json: { ...c, reply: question, next: 'qual_0' } }];

const c = $input.first().json;
const qs = c.qualQuestions || [];
const currentIdx = c.qualStage !== null ? c.qualStage : 0;
const nextIdx = currentIdx + 1;
let qualAnswers = c.qualAnswers || {};
if (qs[currentIdx]) qualAnswers[qs[currentIdx]] = c.userText;
let reply, next;
if (nextIdx < qs.length) {
  reply = qs[nextIdx];
  next = 'qual_' + nextIdx;
} else {
  const flow = c.flow || {};
  const firstStage = Object.keys(flow.stages || {}).filter(k => k !== 'new')[0] || 'new';
  const action = (flow.stages?.[firstStage] || {})['*'] || { next: firstStage, msg: null };
  const vars = flow.variables || {};
  reply = (flow.messages?.[action.msg] || 'Great, thanks! Let me share some information 😊').replace(/\[(\w+)\]/g, (_,k)=> vars[k] ?? '');
  next = action.next || firstStage;
}
return [{ json: { ...c, reply, next, qualAnswers } }];

// Pull full context — try each source until we get one with client_id
let sc = null;
const _nodesToTry = ['Code · Intent + flow', 'Code · State', 'Code · Build ctx'];
for (const n of _nodesToTry) {
  try { const t = $(n).first().json; if (t && t.client_id) { sc = t; break; } } catch(e) {}
}
if (!sc) sc = $input.first().json;
const route = sc.route || 'stage';

let reply = sc.reply;
let next = sc.next;
const qualAnswers = sc.qualAnswers || {};

if (route === 'drop') {
  reply = null;
} else if (route === 'faq') {
  try { reply = $('Code · FAQ reply').first().json.reply || reply; } catch(e) {}
} else if (route === 'qualify') {
  try { const qn = $('Code · Qual start').first().json; reply = qn.reply; next = qn.next; } catch(e) {}
}

const history = (sc.history || []).slice();
if (sc.userText) history.push({ role: 'user', content: sc.userText });
if (reply) history.push({ role: 'assistant', content: reply });

const isHuman = route === 'human';
const body = {
  ClientId: String(sc.client_id),
  Phone: sc.phone, Name: sc.name, ConversationID: sc.convId,
  Date: new Date().toISOString(), Language: sc.language,
  ConvHistory: JSON.stringify(history.slice(-40)),
  LastMsgAt: new Date().toISOString()
};
if (qualAnswers && Object.keys(qualAnswers).length) body.QualAnswers = JSON.stringify(qualAnswers);
if (isHuman) { body.Stage = 'human_handover'; body.Handover = 'Yes'; }
else { body.Stage = next; }
// Increment FAQ count while bot is in post-handover mode
if (sc.stage === 'human_handover' && sc.route !== 'drop') {
  body.HandoverFaqCount = (sc.handoverFaqCount || 0) + 1;
}
if (!isHuman && next !== sc.stage) {
  body['Follow up 1']='No'; body['Follow up 2']='No'; body['Follow up 3']='No';
}
if (sc.intentData?.booking_time) body.BookingTime = sc.intentData.booking_time;
let score = 'Cold';
if (sc.intent === 'BOOKING' || sc.intentData?.booking_time || body.Stage === 'consultation_booked') score = 'Hot';
else if (['AFFIRMATIVE','WATCHED','FORM_DONE'].includes(sc.intent) && sc.stage !== 'new') score = 'Warm';
else if (sc.stage !== 'new' && (sc.history||[]).length > 2) score = 'Warm';
body.Score = score;
if (sc.isDuplicate) body.IsDuplicate = 'Yes';
if (sc._isOptOut) body.OptOut = 'Yes';
if (sc._isResub) { body.OptOut = 'No'; body.Stage = 'new'; }
// Hot moment detection
const HOT_PHRASES = ['how much','price','cost','available','when can','book','ready to','interested in','want to','sign up','start','confirm','deposit','payment','package','deal','offer','buy','purchase','enroll','register'];
const msgLower = (sc.userText||'').toLowerCase();
const hotPhrase = HOT_PHRASES.find(p => msgLower.includes(p));
if (hotPhrase) { body.HotMoment = 'Yes'; body.HotMomentText = (sc.userText||'').slice(0,200); }
// Auto-qualify score (1-10)
const _flow = sc.flow || {};
const _stageKeys = Object.keys((_flow.stages||{})).filter(k=>k!=='new');
const _stageIdx = _stageKeys.indexOf(sc.stage);
const _stageProgress = _stageKeys.length > 0 ? (_stageIdx+1)/_stageKeys.length : 0;
const _histLen = (sc.history||[]).length;
let _qualScore = Math.round((_stageProgress*4) + (score==='Hot'?3:score==='Warm'?2:0) + (hotPhrase?1.5:0) + Math.min(_histLen/20,1.5));
_qualScore = Math.max(1, Math.min(10, _qualScore));
body.QualScore = _qualScore;
const method = sc.leadId ? 'PATCH' : 'POST';
if (sc.leadId) body.Id = sc.leadId;
return [{ json: { ...sc, reply, next, qualAnswers, _method: method, _body: body } }];

const c = $('Code · Prep lead').first().json;
const upsertResult = $input.first().json;
const isError = !!(upsertResult.error || upsertResult.msg);
const responseMs = Date.now() - (c._startMs || Date.now());
return [{ json: {
  ...c,
  _analyticsBody: {
    ClientId: String(c.client_id),
    ClientName: c.client_name || '',
    Phone: c.phone,
    Intent: c.intent || '',
    Route: c.route || '',
    Stage: c.stage || '',
    NextStage: c.next || '',
    ResponseMs: responseMs,
    IsError: isError,
    ErrorMsg: isError ? JSON.stringify(upsertResult).substring(0, 200) : '',
    Timestamp: new Date().toISOString()
  }
} }];

const state = $('Code · State').first().json;
let reply = '';
const tries = ['Code · FAQ reply','Code · Qual start','Code · Qual next','Code · Intent + flow'];
for (const n of tries) {
  try { const r = $(n).first().json.reply; if (r) { reply = r; break; } } catch(e) {}
}
return [{ json: { ...state, _ttsText: reply.slice(0, 500) } }];

const prev = $('Code · Collect reply').first().json;
const resp = $input.first().json;
// Sarvam TTS returns { audios: ['<base64_mp3>'] }
const base64Audio = resp?.audios?.[0] || '';
if (!base64Audio) return [{ json: { ...prev, _ttsOk: false } }];
return [{
  json: { ...prev, _ttsOk: true },
  binary: {
    data: {
      data: base64Audio,
      mimeType: 'audio/mpeg',
      fileName: 'voice-reply.mp3',
      fileExtension: 'mp3'
    }
  }
}];
